import React from "react";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
);

const VerticalGraph = ({ data }) => {
  if (!data || !data.labels?.length) {
    return <p>No graph data available</p>;
  }

  const options = {
    responsive: true,
    plugins: {
      legend: { position: "top" },
      title: {
        display: true,
        text: "Portfolio Price Comparison",
      },
    },
  };

  return (
    <div style={{ width: "100%", maxWidth: "900px", margin: "40px auto" }}>
      <Bar options={options} data={data} />
    </div>
  );
};

export default VerticalGraph;
